ign:center;margin-bottom:48px}\n.mkt-label{font-family:\'JetBrains Mono\',monospace;font-size:13px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:12px}\n.mkt-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;margin:0 0 16px;padding:0;line-height:1.2}\n.mkt-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:#666;max-width:700px;margin:0 auto;line-height:1.6;padding:0}\n.mkt-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.mkt-card{background:#fff;border-radius:16px;padding:32px;border:1px solid #e8eef3}\n.mkt-stat{font-family:\'JetBrains Mono\',monospace;font-size:32px;font-weight:700;margin-bottom:12px;line-height:1}\n.mkt-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 8px;padding:0}\n.mkt-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#666;line-height:1.6;margin:0;padding:0}\n@media(max-width:1024px){\n  .mkt-grid{grid-template-columns:repeat(2,1fr)}\n  .mkt-section{padding:70px 0}\n  .mkt-header{margin-bottom:40px}\n}\n@media(max-width:768px){\n  .mkt-section{padding:60px 0}\n  .mkt-grid{grid-template-columns:1fr}\n  .mkt-title{font-size:28px}\n  .mkt-header{margin-bottom:32px}\n}\n@media(prefers-reduced-motion:reduce){}\n/* === FINAL CTA: READY TO DISCUSS === */\n.pp-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pp-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.pp-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.pp-cta-super-d{position:absolute;top:50%;right:auto;left:50%;width:80%;min-height:80vh;background:url("data:image/svg+xml;base64,") no-repeat center center;background-size:contain;transform:translate(-50%, -50%);opacity:0.12;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n.pp-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:160px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.3;z-index:1;pointer-events:none}\n.pp-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.pp-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.pp-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .pp-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .pp-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .pp-cta-container p{padding-bottom:0 !important}\n\n.pp-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.pp-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.pp-cta-btn:hover::before{left:100%}\n.pp-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.pp-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.pp-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.pp-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.pp-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.pp-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .pp-cta-title{font-size:28px;margin-bottom:16px}\n  .pp-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .pp-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .pp-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.pp-cta-btn{transition:none !important}.pp-cta-btn::before{display:none}}\n.pp-cta-title{font-size:40px;line-height:1.6;letter-spacing:normal;margin-bottom:16px}\n.pp-cta-subtitle{font-size:18px;line-height:1.6;max-width:600px;margin-bottom:40px}\n.pp-cta-btn--primary{color:#0369a1}\n.pp-cta-btn-row{gap:16px}\n.pp-cta-footer-text{text-align:center;max-width:600px;margin:24px auto 20px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);position:relative;z-index:3}\n.pp-cta-footer-text strong{font-weight:600;color:rgba(255,255,255,0.9)}\n.pp-cta-footer-text a{color:#7EC8F2;text-decoration:underline;transition:color 0.2s}\n.pp-cta-footer-text a:hover{color:#fff}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Partner Program"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Partner Program: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Partner Program: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pp-hero-section">\n      <div class="pp-hero-deco-left" aria-hidden="true"></div>\n      <div class="pp-hero-deco-right" aria-hidden="true"></div>\n      <div class="pp-hero-bg" aria-hidden="true"></div>\n      <div class="pp-hero-grain" aria-hidden="true"></div>\n      <div class="pp-hero-inner">\n        <div class="pp-hero-badge">\n          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="8.5" cy="7" r="4"/><path d="M20 8v6M23 11h-6"/></svg>\n          For ERP Implementers &amp; IT Consultants\n        </div>\n        <h1 class="pp-hero-title">Tired of Selling <span class="pp-hero-hl">Man-Days?</span><br>The Problem Isn’t Your Team.</h1>\n        <p class="pp-hero-subtitle">You’re fighting customization wars that burn out your best consultants and compress your margins every year. The problem isn’t execution — it’s your business model. We offer a different architecture.</p>\n        <div class="pp-hero-ctas">\n          <a href="/demo/" class="pp-hero-btn pp-hero-btn--primary">Let’s Talk Partnership</a>\n          <a href="/partner-program/economics/" class="pp-hero-btn pp-hero-btn--ghost">See the Math First</a>\n        </div>\n        <div class="pp-hero-stats">\n          <div class="pp-hero-stat">\n            <div class="pp-hero-stat-value">100%</div>\n            <div class="pp-hero-stat-label">Service Fees You Keep</div>\n          </div>\n          <div class="pp-hero-stat">\n            <div class="pp-hero-stat-value">30–40%</div>\n            <div class="pp-hero-stat-label">License Margin</div>\n          </div>\n          <div class="pp-hero-stat">\n            <div class="pp-hero-stat-value">Recurring</div>\n            <div class="pp-hero-stat-label">Annual Maintenance Revenue</div>\n          </div>\n          <div class="pp-hero-stat">\n            <div class="pp-hero-stat-value">6 mo</div>\n            <div class="pp-hero-stat-label">Lead Lock Protection</div>\n          </div>\n        </div>\n      </div>\n    </div><script>(function(){var c=document.querySelector(\'.pp-hero-bg\');if(c){c.innerHTML=\'<svg viewBox="0 0 1200 700" preserveAspectRatio="xMidYMid slice" aria-hidden="true"><defs><linearGradient id="pp-bar-fade" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" stop-color="#00AFF0" stop-opacity="0.15"/><stop offset="100%" stop-color="#00AFF0" stop-opacity="0"/></linearGradient></defs><g transform="translate(850,200)" opacity="0.12"><rect x="0" y="280" width="280" height="40" rx="6" fill="#00AFF0"/><rect x="0" y="230" width="280" height="40" rx="6" fill="#00AFF0"/><rect x="0" y="180" width="280" height="40" rx="6" fill="#00AFF0"/><rect x="0" y="130" width="280" height="40" rx="6" fill="#00AFF0"/><rect x="0" y="80" width="280" height="40" rx="6" fill="#00AFF0"/><path d="M320 300 L320 60" stroke="#00AFF0" stroke-width="3" opacity="0.6"/><path d="M310 80 L320 55 L330 80" fill="none" stroke="#00AFF0" stroke-width="3" opacity="0.6"/></g><g opacity="0.04"><line x1="0" y1="150" x2="1200" y2="150" stroke="#fff" stroke-width="1"/><line x1="0" y1="300" x2="1200" y2="300" stroke="#fff" stroke-width="1"/><line x1="0" y1="450" x2="1200" y2="450" stroke="#fff" stroke-width="1"/><line x1="0" y1="600" x2="1200" y2="600" stroke="#fff" stroke-width="1"/><line x1="300" y1="0" x2="300" y2="700" stroke="#fff" stroke-width="1"/><line x1="600" y1="0" x2="600" y2="700" stroke="#fff" stroke-width="1"/><line x1="900" y1="0" x2="900" y2="700" stroke="#fff" stroke-width="1"/></g><g opacity="0.08"><circle cx="950" cy="150" r="8" fill="#00AFF0"/><circle cx="1050" cy="200" r="6" fill="#00AFF0"/><circle cx="1000" cy="350" r="10" fill="#00AFF0"/><circle cx="1100" cy="450" r="5" fill="#00AFF0"/><line x1="950" y1="150" x2="1050" y2="200" stroke="#00AFF0" stroke-width="1"/><line x1="1050" y1="200" x2="1000" y2="350" stroke="#00AFF0" stroke-width="1"/><line x1="1000" y1="350" x2="1100" y2="450" stroke="#00AFF0" stroke-width="1"/></g></svg>\';}})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Revenue Model"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Revenue Model: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Revenue Model: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="reality-section reality-section--revenue" style="background:#fff">\n      <div class="reality-wave-fade" aria-hidden="true"></div>\n      <div class="reality-scene-revenue reality-scene" aria-hidden="true"></div>\n      <div class="reality-inner">\n        <div class="reality-header">\n          <h2 class="reality-title">The Revenue Model Pain</h2>\n          <p class="reality-subtitle">You know these patterns. We’ve heard them from every systems integrator we’ve talked to. The profit squeeze is structural, not circumstantial.</p>\n        </div>\n        <div class="reality-grid">\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M3 3v18h18"/><path d="M18 17V9"/><path d="M13 17V5"/><path d="M8 17v-3"/></svg></div>\n          <h3>The “Margin Erosion” Crisis</h3>\n          <p>Your project margins have silently compressed from <strong>35% to 18%</strong> over the last few years. Clients demand Tier-1 capabilities (IoT, real-time costing) but refuse to pay more than Tier-3 prices.</p>\n        </div>\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></div>\n          <h3>The “Unbillable Overrun”</h3>\n          <p>You spend weeks fixing data errors or creating workarounds for rigid software (phantom BOMs, regrind logic) that you <strong>cannot bill for</strong>, turning profitable projects into break-even disasters.</p>\n        </div>\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg></div>\n          <h3>The “Ghost IT” Burden</h3>\n          <p>You aren’t just their ERP consultant — you’ve become their unpaid IT department. <strong>Many Thai SMEs</strong> lack a dedicated IT manager, so your senior staff wastes billable hours on Wi-Fi troubleshooting and password resets.</p>\n        </div>\n        </div>\n        \n      </div>\n    </div><script>(function(){var c=document.querySelector(\'.reality-scene-revenue\');if(c){c.innerHTML=\'<svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice" aria-hidden="true"><rect x="150" y="550" width="50" height="250" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.25"/><rect x="240" y="450" width="50" height="350" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.3"/><rect x="330" y="370" width="50" height="430" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.3"/><rect x="420" y="320" width="50" height="480" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.35"/><rect x="510" y="300" width="50" height="500" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.35"/><rect x="600" y="290" width="50" height="510" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.3"/><rect x="690" y="285" width="50" height="515" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.25"/><line x1="100" y1="270" x2="800" y2="270" stroke="#00AFF0" stroke-width="2.5" stroke-dasharray="12 8" opacity="0.3"/><circle cx="1050" cy="350" r="90" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/><line x1="1050" y1="350" x2="1050" y2="280" stroke="#000864" stroke-width="2.5" opacity="0.18" stroke-linecap="round"/><line x1="1050" y1="350" x2="1100" y2="370" stroke="#000864" stroke-width="2" opacity="0.15" stroke-linecap="round"/><circle cx="1050" cy="350" r="4" fill="#000864" opacity="0.25"/><circle cx="180" cy="300" r="3" fill="#000864" opacity="0.15"/><circle cx="750" cy="400" r="3" fill="#00AFF0" opacity="0.15"/></svg>\';}})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Operational"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Operational: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Pain: Operational: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="reality-section reality-section--operational" style="background:#f8fafc">\n      \n      <div class="reality-scene-operational reality-scene" aria-hidden="true"></div>\n      <div class="reality-inner">\n        <div class="reality-header">\n          <h2 class="reality-title">The Operational Pain</h2>\n          <p class="reality-subtitle">Your best people are burning out. Not from hard work—from the wrong work.</p>\n        </div>\n        <div class="reality-grid">\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M17 18a5 5 0 0 0-10 0"/><line x1="12" y1="2" x2="12" y2="9"/><line x1="4.22" y1="10.22" x2="5.64" y2="11.64"/><line x1="1" y1="18" x2="3" y2="18"/><line x1="21" y1="18" x2="23" y2="18"/><line x1="18.36" y1="11.64" x2="19.78" y2="10.22"/><line x1="23" y1="22" x2="1" y2="22"/><polyline points="8 6 12 2 16 6"/></svg></div>\n          <h3>Consultant Burnout</h3>\n          <p>Your senior consultants are quitting—not for salary, but because they’re tired of being <strong>“data babysitters.”</strong> They spend 50% of their time watching warehouse staff type numbers instead of doing solution architecture.</p>\n        </div>\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg></div>\n          <h3>The “Knowledge Ceiling”</h3>\n          <p>You cannot scale beyond ~35 people because delivery relies on a few “hero” seniors. If one quits, it costs you <strong>฿200,000 in recruitment plus 6 months</strong> of lost productivity.</p>\n        </div>\n        <div class="reality-card">\n          <div class="reality-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="8.5" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg></div>\n          <h3>The “Sales vs. Delivery” War</h3>\n          <p>Sales promises “customized flexibility” to win deals. Delivery tries to force a rigid ERP to bend. This <strong>perpetual conflict</strong> drains morale and profit on every single project.</p>\n        </div>\n        </div>\n        <div class="reality-cta-wrap"><a href="/partner-program/business-model/" class="reality-cta-btn">Read the Full Diagnosis →</a></div>\n      </div>\n    </div><script>(function(){var c=document.querySelector(\'.reality-scene-operational\');if(c){c.innerHTML=\'<svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice" aria-hidden="true"><path d="M100 700 Q300 680 500 650 Q700 600 900 580 Q1100 560 1300 550" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/><path d="M100 750 Q300 740 500 720 Q700 700 900 690 Q1100 680 1300 675" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/><rect x="200" y="200" width="120" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/><line x1="220" y1="230" x2="300" y2="230" stroke="#000864" stroke-width="0.5" opacity="0.12"/><line x1="220" y1="245" x2="280" y2="245" stroke="#000864" stroke-width="0.5" opacity="0.12"/><line x1="220" y1="260" x2="290" y2="260" stroke="#000864" stroke-width="0.5" opacity="0.12"/><path d="M320 240 L400 240" stroke="#000864" stroke-width="1.5" opacity="0.15"/><polygon points="395,235 410,240 395,245" fill="#000864" opacity="0.15"/><rect x="410" y="200" width="120" height="80" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/><path d="M530 240 L610 240" stroke="#000864" stroke-width="1.5" opacity="0.12"/><polygon points="605,235 620,240 605,245" fill="#000864" opacity="0.12"/><path d="M620 240 Q700 240 700 280 Q700 320 620 320 L530 320" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12" stroke-dasharray="6 4"/><circle cx="1100" cy="300" r="70" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/><line x1="1100" y1="300" x2="1100" y2="245" stroke="#000864" stroke-width="2" opacity="0.15" stroke-linecap="round"/><line x1="1100" y1="300" x2="1140" y2="315" stroke="#000864" stroke-width="1.5" opacity="0.12" stroke-linecap="round"/><circle cx="300" cy="500" r="3" fill="#000864" opacity="0.12"/><circle cx="800" cy="450" r="4" fill="#00AFF0" opacity="0.1"/><circle cx="1250" cy="550" r="3" fill="#000864" opacity="0.1"/></svg>\';}})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Alternative Model: Partner-First"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Alternative Model: Partner-First: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Alternative Model: Partner-First: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="alt-section" data-particles>\n      <div class="alt-wave" aria-hidden="true"></div>\n      <div class="alt-inner">\n        <div class="alt-header">\n          <h2 class="alt-title">“You Keep the Meat, We Drink the Soup”</h2>\n          <p class="alt-subtitle">Unlike global vendors who use partners as low-margin resellers, we deliberately give partners the high-margin revenue so you have a reason to grow with us.</p>\n        </div>\n\n        <div class="alt-comparison">\n          <div class="alt-model alt-model-old">\n            <span class="alt-model-label alt-model-label--old">Typical Vendor Model</span>\n            <h3>Vendor Takes the Meat</h3>\n            <ul class="alt-model-list"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> Vendor controls pricing and margin</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> Partner is just a reseller channel</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> Direct team competes for your deals</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> Maintenance revenue goes to HQ</li></ul>\n          </div>\n          <div class="alt-arrow"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></div>\n          <div class="alt-model alt-model-new">\n            <span class="alt-model-label alt-model-label--new">DigiWin Partner-First Model</span>\n            <h3>Partner Keeps the Meat</h3>\n            <ul class="alt-model-list"><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg> <strong>100%</strong> of implementation &amp; service fees</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg> <strong>30–40%</strong> margin on license sales</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg> <strong>Zero</strong> channel conflict—Thai market is yours</li><li><svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg> <strong>Recurring</strong> maintenance revenue—you set the rate</li></ul>\n          </div>\n        </div>\n\n        <div class="alt-benefits">\n        <div class="alt-benefit">\n          <div class="alt-benefit-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg></div>\n          <h3>Your Market, Not Ours</h3>\n          <p>Our direct team handles Chinese/Taiwanese-owned factory inbound only. We don’t compete for Thai SME deals because <strong>your local relationships are the asset we can’t replicate</strong>.</p>\n        </div>\n        <div class="alt-benefit">\n          <div class="alt-benefit-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/></svg></div>\n          <h3>Deal Registration Protection</h3>\n          <p>Once you book a lead, it is <strong>locked to you for 6 months</strong>. Our direct team or other partners cannot undercut your groundwork. It’s in the Master Agreement.</p>\n        </div>\n        <div class="alt-benefit">\n          <div class="alt-benefit-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg></div>\n          <h3>Land &amp; Expand Strategy</h3>\n          <p>Enter clients with lower-risk <strong>MES or Workflow iGP</strong> projects, then expand to full ERP once trust is established. Each phase generates revenue while deepening the relationship.</p>\n        </div>\n        </div>\n\n        <div class="alt-cta-wrap">\n          <a href="/demo/" class="alt-cta-btn">Let’s Talk Partnership</a>\n          <p class="alt-cta-note">30-minute conversation. We’ll walk through your current portfolio and show you where DigiWin fits.</p>\n        </div>\n      </div>\n    </div>\n    <script>/**\n * DigiWin 数据洋流 (Data Ocean Current)\n *\n * Recreates the brand kit\'s signature visual: a 3D dot-grid surface\n * with dramatic rolling wave crests, viewed from a low angle.\n * Reference: DigiWin 2025 Annual Report cover, brand kit pp.61-68.\n *\n * Usage:\n *   <section data-particles>              — subtle on light bg (default)\n *   <section data-particles="bold">       — vivid on dark navy bg\n *   <section data-particles="medium">     — moderate visibility\n *\n * WordPress: wp_enqueue_script or Code Module. Self-initializing.\n */\n\n(function () {\n    \'use strict\';\n\n    var reducedMotion = window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n    var PI2 = Math.PI * 2;\n\n    // ── Brand colors (RGB) ──────────────────────────────────────────\n    var BLUE = [0, 175, 240];   // #00AFF0 Smart Blue\n    var CYAN = [0, 230, 255];   // #00E6FF Cyan accent\n\n    // ── Presets ─────────────────────────────────────────────────────\n    var PRESETS = {\n        light: {\n            frontOpacity: 0.18,   // visible but not distracting on white/light backgrounds\n            backOpacity: 0.03,\n            frontRadius: 3.5,\n            backRadius: 0.5,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.10\n        },\n        subtle: {\n            frontOpacity: 0.30,   // foreground dot opacity\n            backOpacity: 0.04,    // distant dot opacity\n            frontRadius: 4.5,     // foreground dot size (px)\n            backRadius: 0.6,      // distant dot size (px)\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.12\n        },\n        medium: {\n            frontOpacity: 0.45,\n            backOpacity: 0.06,\n            frontRadius: 5.0,\n            backRadius: 0.8,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.18\n        },\n        bold: {\n            frontOpacity: 0.60,\n            backOpacity: 0.10,\n            frontRadius: 5.5,\n            backRadius: 1.0,\n            color: CYAN,\n            colorAlt: BLUE,\n            altRatio: 0.25\n        }\n    };\n\n    // ── Utility ─────────────────────────────────────────────────────\n    function lerp(a, b, t) { return a + (b - a) * t; }\n\n    // ── DataOcean class ─────────────────────────────────────────────\n    function DataOcean(el) {\n        this.el = el;\n        this.canvas = null;\n        this.ctx = null;\n        this.w = 0;\n        this.h = 0;\n        this.dpr = Math.min(window.devicePixelRatio || 1, 2);\n        this.visible = false;\n        this.raf = null;\n        this.time = 0;\n        this.resizeTimer = null;\n        this.colors = null; // pre-assigned per grid point\n\n        this.opts = this._parseOpts();\n        this._setup();\n        this._buildColors();\n        this._observe();\n\n        if (!reducedMotion) {\n            this._loop();\n        } else {\n            this.visible = true;\n            this._draw(0);\n        }\n    }\n\n    DataOcean.prototype._parseOpts = function () {\n        var name = this.el.getAttribute(\'data-particles\') || \'subtle\';\n        if (name === \'\' || name === \'true\') name = \'subtle\';\n        return PRESETS[name] || PRESETS.subtle;\n    };\n\n    DataOcean.prototype._setup = function () {\n        var c = document.createElement(\'canvas\');\n        c.setAttribute(\'aria-hidden\', \'true\');\n        c.style.cssText = \'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n        var pos = getComputedStyle(this.el).position;\n        if (pos === \'static\') this.el.style.position = \'relative\';\n        this.el.style.overflow = \'hidden\';\n        this.el.insertBefore(c, this.el.firstChild);\n        this.canvas = c;\n        this.ctx = c.getContext(\'2d\');\n        this._resize();\n\n        var self = this;\n        window.addEventListener(\'resize\', function () {\n            clearTimeout(self.resizeTimer);\n            self.resizeTimer = setTimeout(function () {\n                self._resize();\n                self._buildColors();\n            }, 200);\n        });\n    };\n\n    DataOcean.prototype._resize = function () {\n        var r = this.el.getBoundingClientRect();\n        this.w = r.width;\n        this.h = r.height;\n        this.canvas.width = this.w * this.dpr;\n        this.canvas.height = this.h * this.dpr;\n        this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);\n    };\n\n    // Grid: ~55 cols × ~35 rows. Pre-assign a color to each dot.\n    DataOcean.prototype._buildColors = function () {\n        var cols = Math.min(65, Math.ceil(this.w / 22) + 4);\n        var rows = 35;\n        this._cols = cols;\n        this._rows = rows;\n        var n = cols * rows;\n        this.colors = new Array(n);\n        var alt = this.opts.altRatio;\n        for (var i = 0; i < n; i++) {\n            this.colors[i] = Math.random() < alt ? this.opts.colorAlt : this.opts.color;\n        }\n    };\n\n    DataOcean.prototype._observe = function () {\n        var self = this;\n        if (\'IntersectionObserver\' in window) {\n            this._obs = new IntersectionObserver(function (e) {\n                self.visible = e[0].isIntersecting;\n            }, { rootMargin: \'150px 0px\' });\n            this._obs.observe(this.el);\n        } else {\n            this.visible = true;\n        }\n    };\n\n    DataOcean.prototype._loop = function () {\n        var self = this;\n        var last = 0;\n        (function tick(ts) {\n            self.raf = requestAnimationFrame(tick);\n            if (!self.visible) return;\n            if (ts - last < 30) return; // ~30 fps\n            last = ts;\n            self.time += 0.006;\n            self._draw(self.time);\n        })(0);\n    };\n\n    /**\n     * ── Core renderer ───────────────────────────────────────────────\n     *\n     * Approach: Think of a flat grid of dots on a table, viewed from a\n     * low angle. The table surface undulates with large rolling waves.\n     *\n     * "depth" goes from 0 (nearest / bottom of screen) to 1 (farthest /\n     * top area). Everything scales with depth:\n     *   - dot size shrinks\n     *   - dot opacity fades\n     *   - vertical row spacing compresses (perspective foreshortening)\n     *   - horizontal dot spacing tightens\n     *   - wave amplitude diminishes\n     *\n     * The wave function creates 2-3 visible rolling crests that sweep\n     * diagonally across the surface — matching the annual report cover.\n     */\n    DataOcean.prototype._draw = function (t) {\n        var ctx = this.ctx;\n        var w = this.w;\n        var h = this.h;\n        var opts = this.opts;\n        var cols = this._cols;\n        var rows = this._rows;\n\n        ctx.clearRect(0, 0, w, h);\n\n        // ── Perspective layout ──────────────────────────────────────\n        //\n        // The wave occupies the bottom ~55% of the section.\n        // "horizon" is where distant rows converge (top of wave area).\n        // "ground" is the bottom edge of the section.\n\n        var ground = h + 10;               // bottom edge (+ small overflow)\n        var horizon = h * 0.35;            // where distant dots vanish toward\n        var totalSpan = ground - horizon;   // vertical pixel range for the wave\n\n        var idx = 0;\n\n        // Draw back-to-front for correct visual layering\n        for (var row = rows - 1; row >= 0; row--) {\n\n            // ── Depth (0 = near/bottom, 1 = far/top) ───────────────\n            var depth = row / (rows - 1);\n\n            // Non-linear depth mapping: compress more toward horizon\n            // This creates the "accelerating compression" of perspective\n            var mappedDepth = Math.pow(depth, 0.55);\n\n            // Screen Y baseline for this row (no wave yet)\n            var baseY = ground - mappedDepth * totalSpan;\n\n            // ── Per-row properties (lerp by depth) ──────────────────\n            var dotR = lerp(opts.frontRadius, opts.backRadius, depth);\n            var dotA = lerp(opts.frontOpacity, opts.backOpacity, depth);\n            var colSpacing = lerp(w / (cols - 4), w / (cols + 15), depth);\n\n            // Slight horizontal offset per row (creates diagonal sweep)\n            var rowShift = depth * w * 0.12;\n\n            // ── Wave: two layers for organic rolling feel ───────────\n            //\n            // Primary wave: large rolling crests (creates the signature look)\n            // Secondary wave: smaller ripple for naturalism\n            //\n            // Wave amplitude is BIG near foreground and diminishes with depth.\n            // This is what makes the crests dramatically visible.\n\n            var waveScale = (1 - depth * 0.75); // waves diminish into distance\n            var amp1 = 70 * waveScale;           // primary crest amplitude (px)\n            var amp2 = 25 * waveScale;           // secondary ripple\n\n            for (var col = 0; col < cols; col++) {\n                // Screen X\n                var screenX = col * colSpacing - rowShift + colSpacing * 0.5;\n\n                // Wrap X for seamless edge handling\n                if (screenX < -30 || screenX > w + 30) { idx++; continue; }\n\n                // ── Wave displacement ───────────────────────────────\n                //\n                // The primary wave sweeps diagonally (uses both col and row).\n                // freq values tuned so ~2 full crests are visible across width.\n\n                var worldX = col * 24; // stable world-space coordinate for wave\n                var worldZ = row * 18;\n\n                var wave = amp1 * Math.sin(\n                    worldX * 0.0065 + worldZ * 0.012 + t * 0.9\n                );\n                wave += amp2 * Math.sin(\n                    worldX * 0.013 - worldZ * 0.008 + t * 0.55 + 1.8\n                );\n\n                var screenY = baseY - wave;\n\n                // Skip if outside visible area\n                if (screenY < -15 || screenY > h + 15) { idx++; continue; }\n\n                // ── Draw dot ────────────────────────────────────────\n                var c = this.colors[idx % this.colors.length];\n                ctx.beginPath();\n                ctx.arc(screenX, screenY, dotR, 0, PI2);\n                ctx.fillStyle = \'rgba(\' + c[0] + \',\' + c[1] + \',\' + c[2] + \',\' + dotA + \')\';\n                ctx.fill();\n\n                idx++;\n            }\n        }\n    };\n\n    DataOcean.prototype.destroy = function () {\n        if (this.raf) cancelAnimationFrame(this.raf);\n        if (this._obs) this._obs.disconnect();\n        if (this.canvas && this.canvas.parentNode) {\n            this.canvas.parentNode.removeChild(this.canvas);\n        }\n    };\n\n    // ── Auto-init ───────────────────────────────────────────────────\n    function init() {\n        var els = document.querySelectorAll(\'[data-particles]\');\n        var inst = [];\n        for (var i = 0; i < els.length; i++) inst.push(new DataOcean(els[i]));\n\n        window.DigiWinParticleOcean = {\n            instances: inst,\n            DataOcean: DataOcean,\n            refresh: function () {\n                for (var j = 0; j < inst.length; j++) inst[j].destroy();\n                inst = [];\n                var els2 = document.querySelectorAll(\'[data-particles]\');\n                for (var k = 0; k < els2.length; k++) inst.push(new DataOcean(els2[k]));\n                this.instances = inst;\n            }\n        };\n    }\n\n    if (document.readyState === \'loading\') {\n        document.addEventListener(\'DOMContentLoaded\', init);\n    } else {\n        init();\n    }\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"What You Get: Partner Offerings"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"What You Get: Partner Offerings: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"What You Get: Partner Offerings: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="offer-section">\n      <div class="offer-inner">\n        <div class="offer-header">\n          <h2 class="offer-title">What You Get as a DigiWin Partner</h2>\n          <p class="offer-subtitle">A product stack built for manufacturing, transparent margin structures, and the support infrastructure to make your first deals profitable.</p>\n        </div>\n\n        <div class="offer-cards">\n        <a href="/partner-program/solutions/" class="offer-card">\n          <div class="offer-card-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="6"/><circle cx="12" cy="12" r="2"/></svg></div>\n          <div class="offer-card-content">\n            <h3>The Solution Stack</h3>\n            <p>Proven products to resell: ERP, MES, WMS, AIoT. <span class="dw-years">44</span> years of development. 50,000+ installations worldwide. Products that work in real factories.</p>\n            <span class="offer-card-link">View Product Portfolio <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>\n          </div>\n        </a>\n        <a href="/partner-program/economics/" class="offer-card">\n          <div class="offer-card-icon"><svg viewBox="0 0 24 24" stroke-width="2" aria-hidden="true"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg></div>\n          <div class="offer-card-content">\n            <h3>Partner Economics</h3>\n            <p>Transparent margins, predictable revenue share, and multi-year projections that show how partnership compounds your business value over time.</p>\n            <span class="offer-card-link">See the Numbers <svg viewBox="0 0 24 24" fill="none" stroke-width="2" aria-hidden="true"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>\n          </div>\n        </a>\n        </div>\n\n        <div class="offer-box">\n          <div class="offer-box-inner">\n            <h3 class="offer-box-title">Partner Benefits at a Glance</h3>\n            <div class="offer-checks"><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Protected territory rights</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Technical certification</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Sales enablement support</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Marketing co-investment</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Implementation methodology</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Ongoing product updates</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>6-month lead lock protection</span></div><div class="offer-check-item"><svg viewBox="0 0 24 24" fill="none" stroke-width="2.5" aria-hidden="true"><polyline points="20 6 9 17 4 12"/></svg><span>Annual partner summit</span></div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div><script>(function(){var y=new Date().getFullYear()-1982;document.querySelectorAll(\'.dw-years\').forEach(function(e){e.textContent=y});})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: Continue Your Research"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: Continue Your Research: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: Continue Your Research: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="journey-section journey-section--research" style="background:linear-gradient(180deg, #f8fafc 0%, #fff 100%)">\n      <div class="journey-inner">\n        <div class="journey-header">\n          <h2 class="journey-title">Continue Your Research</h2>\n          <p class="journey-subtitle">You’re skeptical—good. Explore the details before we talk.</p>\n        </div>\n        <div class="journey-steps journey-steps--line">\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #00AFF0, #003CC8)"><span>1</span></div>\n          <h3>Deepen the “Why”</h3>\n          <p>Understand why your margin erosion is <em>structural</em>, not circumstantial. See if the diagnosis matches your reality.</p>\n          <a href="/partner-program/business-model/" class="journey-step-cta">The Evolving Business Model →</a>\n        </div>\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #00AFF0, #003CC8)"><span>2</span></div>\n          <h3>Evaluate the “Weapon”</h3>\n          <p>See if DigiWin gives you a better weapon to fight the price war against low-cost ERP vendors and specialized MES providers.</p>\n          <a href="/partner-program/solutions/" class="journey-step-cta">The Solution Stack →</a>\n        </div>\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #00AFF0, #003CC8)"><span>3</span></div>\n          <h3>Verify the “Math”</h3>\n          <p>Run the numbers yourself. Realistic projections in Thai Baht, conservative scenarios, and the actual margin structure.</p>\n          <a href="/partner-program/economics/" class="journey-step-cta">Partner Economics →</a>\n        </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: How You Grow"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: How You Grow: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: How You Grow: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="journey-section journey-section--tiers" style="background:#fff">\n      <div class="journey-inner">\n        <div class="journey-header">\n          <h2 class="journey-title">How You Grow With Us</h2>\n          <p class="journey-subtitle">Clear milestones define your progression from co-delivery to full autonomy — and higher margins at every stage.</p>\n        </div>\n        <div class="journey-steps journey-steps--line">\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #94a3b8, #5b6b80)"><span>R</span></div>\n          <h3>Ready (Entry)</h3>\n          <p><strong>Competitive margin from Day 1</strong><br>Co-delivery required. We work your first projects together. Earn while you learn.</p>\n          \n        </div>\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #a8a29e, #78716c)"><span>S</span></div>\n          <h3>Silver (Collaborative)</h3>\n          <p><strong>Strong margin</strong><br>Supervised delivery. You lead projects; we provide backend support and escalation.</p>\n          \n        </div>\n        <div class="journey-step">\n          <div class="journey-number" style="background:linear-gradient(135deg, #fbbf24, #d97706)"><span>G</span></div>\n          <h3>Gold (Independent)</h3>\n          <p><strong>Highest-tier margin</strong><br>Full autonomy. You sell, deliver, and support without our direct involvement. Your team, your clients, your business.</p>\n          \n        </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Timing: Why Now"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Timing: Why Now: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Market Timing: Why Now: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mkt-section">\n      <div class="mkt-inner">\n        <div class="mkt-header">\n          <div class="mkt-label">Why Now</div>\n          <h2 class="mkt-title">The Thai Market Window Is Open</h2>\n          <p class="mkt-subtitle">Three converging forces are creating a rare opportunity for ERP partners in Thailand.</p>\n        </div>\n        <div class="mkt-grid">\n        <div class="mkt-card">\n          <div class="mkt-stat" style="color:#b91c1c">2027</div>\n          <h3>Legacy ERP End-of-Life</h3>\n          <p>Legacy enterprise ERP systems are reaching end of maintenance. Thai manufacturers on aging platforms must migrate — and the upgrade path from incumbent vendors is often prohibitively expensive for SMEs. This creates a migration window for manufacturing-focused alternatives.</p>\n        </div>\n        <div class="mkt-card">\n          <div class="mkt-stat" style="color:#b45309">~20</div>\n          <h3>Competitors Scaling Fast</h3>\n          <p>Chinese ERP vendors each now have ~20 staff in Thailand and growing. The window to establish market position is narrowing. Partners who move first lock in territory before competitors build their own channel networks.</p>\n        </div>\n        <div class="mkt-card">\n          <div class="mkt-stat" style="color:#15803d">8,000</div>\n          <h3>Target Factories Identified</h3>\n          <p>From Thailand’s manufacturing base, we’ve identified 8,000 genuine targets. Only 113 are properly qualified so far — leaving 7,000+ untouched opportunities for partners to pursue.</p>\n        </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Ready to Discuss"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Ready to Discuss: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Final CTA: Ready to Discuss: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pp-cta-section">\n    <div class="pp-cta-super-d" aria-hidden="true"></div>\n    <div class="pp-cta-wave-flow" aria-hidden="true"></div>\n    <div class="pp-cta-container">\n      <h2 class="pp-cta-title">Ready to Discuss Your Territory?</h2>\n      <p class="pp-cta-subtitle">A straightforward conversation about <em>your</em> margins, <em>your</em> market, and whether the partnership math works for both sides.</p>\n      <div class="pp-cta-btn-row">\n        <a href="/demo/" class="pp-cta-btn pp-cta-btn--primary">Let’s Talk Partnership</a>\n        <a href="/partner-program/economics/" class="pp-cta-btn pp-cta-btn--ghost">See the Math First</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100555;

