DELETE FROM wp_postmeta WHERE post_id = 100555 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100555, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === PARTNER HERO === */\n.pp-hero-section{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pp-hero-section::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none;z-index:0}\n.pp-hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.pp-hero-grain{position:absolute;inset:0;z-index:1}\n.pp-hero-bg{position:absolute;inset:0;pointer-events:none;overflow:hidden}\n.pp-hero-bg svg{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:100%;max-width:1400px;height:auto;min-height:100%}\n.pp-hero-deco-left{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.14;pointer-events:none;z-index:0}\n.pp-hero-deco-right{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.1;pointer-events:none;z-index:0}\n.pp-hero-inner{max-width:1200px;margin:0 auto;position:relative;z-index:3}\n.pp-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0,175,240,0.2);border:1px solid rgba(0,175,240,0.3);padding:8px 16px;border-radius:50px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:#7EC8F2;margin-bottom:24px}\n.pp-hero-badge svg{stroke:#7EC8F2;flex-shrink:0}\n.pp-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(36px,5vw,56px);font-weight:700;color:#fff;line-height:1.15;margin:0 0 24px;max-width:800px;padding:0}\n.pp-hero-hl{color:#00AFF0}\n.pp-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:680px;margin:0 0 40px;padding:0}\n.pp-hero-ctas{display:flex;gap:16px;flex-wrap:wrap;margin-bottom:60px;position:relative;z-index:2}\n.pp-hero-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;display:inline-flex;align-items:center;gap:8px;border:none;cursor:pointer;line-height:1.6}\n.pp-hero-btn--primary{background:#006dac;color:#fff;box-shadow:0 4px 14px rgba(0,175,240,0.35)}\n.pp-hero-btn--primary:hover{background:#003CC8;transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,175,240,0.45)}\n.pp-hero-btn--ghost{background:rgba(255,255,255,0.12);border:2px solid rgba(255,255,255,0.5);color:#fff;font-size:15px;border-radius:12px}\n.pp-hero-btn--ghost:hover{background:rgba(255,255,255,0.2);border-color:#fff;transform:translateY(-2px)}\n.pp-hero-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:32px;padding-top:40px;border-top:1px solid rgba(255,255,255,0.1)}\n.pp-hero-stat{text-align:center}\n.pp-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#fff;line-height:1;margin-bottom:8px}\n.pp-hero-stat-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.4}\n@media(max-width:1024px){\n  .pp-hero-section{padding:120px 24px 80px}\n  .pp-hero-stats{grid-template-columns:repeat(2,1fr);gap:24px}\n  .pp-hero-bg svg{opacity:0.7;transform:translate(-50%,-50%) scale(1.2)}\n}\n@media(max-width:768px){\n  .pp-hero-section{padding:100px 20px 60px}\n  .pp-hero-stats{grid-template-columns:1fr}\n  .pp-hero-ctas{flex-direction:column;align-items:stretch}\n  .pp-hero-btn{text-align:center;justify-content:center}\n  .pp-hero-bg svg{opacity:0.5;transform:translate(-40%,-50%) scale(1.5)}\n}\n@media(prefers-reduced-motion:reduce){.pp-hero-btn{transition:none !important}}\n/* === REALITY CHECK SECTIONS (S2+S3) === */\n.reality-wave-fade{position:relative;width:100%;height:120px;pointer-events:none;opacity:0.06;margin:-1px 0}\n.reality-section{padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.reality-section--operational{padding-top:60px}\n.reality-scene{position:absolute;inset:0;pointer-events:none;z-index:0}.reality-scene svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n.reality-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.reality-header{text-align:center;max-width:800px;margin:0 auto 60px}\n.reality-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.reality-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.reality-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.reality-card{background:linear-gradient(135deg,#fef2f2 0%,#fff5f5 100%);border:1px solid #fecaca;border-radius:16px;padding:32px;position:relative}\n.reality-icon{width:56px;height:56px;background:linear-gradient(135deg,#dc2626,#b91c1c);border-radius:12px;display:flex;align-items:center;justify-content:center;margin-bottom:20px}\n.reality-icon svg{width:28px;height:28px;stroke:#fff;fill:none}\n.reality-card h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#7f1d1d;line-height:1.6;margin:0 0 12px;padding:0}\n.reality-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#991b1b;line-height:1.6;margin:0;padding:0}\n.reality-cta-wrap{text-align:center;margin-top:48px}\n.reality-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:600;color:#0369a1;background:rgba(0,175,240,0.08);border:1px solid rgba(0,175,240,0.2);padding:12px 28px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;display:inline-block}\n.reality-cta-btn:hover{background:rgba(0,175,240,0.15);border-color:#00AFF0;transform:translateY(-1px)}\n@media(max-width:1024px){\n  .reality-grid{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .reality-section{padding:80px 20px}\n  .reality-section--operational{padding-top:40px}\n  .reality-grid{grid-template-columns:1fr}\n  .reality-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.reality-cta-btn{transition:none !important}}\n/* === ALTERNATIVE MODEL (S4) === */\n.alt-section{background:linear-gradient(180deg,#F5F7FA 0%,#fff 100%);padding:100px 24px 180px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.alt-wave{position:absolute;bottom:0;left:0;right:0;height:200px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.04));pointer-events:none;z-index:0;opacity:0.08}\n.alt-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.alt-header{text-align:center;max-width:860px;margin:0 auto 60px}\n.alt-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.alt-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.alt-comparison{display:grid;grid-template-columns:1fr 80px 1fr;gap:32px;align-items:center;margin-bottom:60px}\n.alt-model{background:#fff;border-radius:20px;padding:40px;box-shadow:0 4px 24px rgba(0,0,0,0.06)}\n.alt-model-old{border:2px solid #fecaca}\n.alt-model-new{border:2px solid #86efac}\n.alt-model-label{display:inline-block;padding:6px 16px;border-radius:50px;font-family:\'Noto Sans\',sans-serif;font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:20px}\n.alt-model-label--old{background:#fee2e2;color:#991b1b}\n.alt-model-label--new{background:#dcfce7;color:#166534}\n.alt-model h3{font-family:\'Noto Sans\',sans-serif;font-size:24px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 24px;padding:0}\n.alt-model-list{list-style:none;padding:0;margin:0}\n.alt-model-list li{display:flex;align-items:flex-start;gap:12px;font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#475569;padding:12px 0;border-bottom:1px solid #f1f5f9}\n.alt-model-list li:last-child{border-bottom:none}\n.alt-model-list li svg{width:20px;height:20px;flex-shrink:0;margin-top:2px}\n.alt-model-old .alt-model-list li svg{stroke:#dc2626}\n.alt-model-new .alt-model-list li svg{stroke:#16a34a}\n.alt-arrow{display:flex;align-items:center;justify-content:center}\n.alt-arrow svg{width:48px;height:48px;stroke:#00AFF0}\n.alt-benefits{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;margin-top:16px}\n.alt-benefit{background:#fff;border:1px solid #e2e8f0;border-radius:16px;padding:32px;transition:all 0.3s ease}\n.alt-benefit:hover{border-color:#00AFF0;box-shadow:0 8px 32px rgba(0,175,240,0.12)}\n.alt-benefit-icon{width:56px;height:56px;background:linear-gradient(135deg,#00AFF0,#003CC8);border-radius:12px;display:flex;align-items:center;justify-content:center;margin-bottom:20px}\n.alt-benefit-icon svg{width:28px;height:28px;stroke:#fff;fill:none}\n.alt-benefit h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 12px;padding:0}\n.alt-benefit p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.alt-cta-wrap{text-align:center;margin-top:56px}\n.alt-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff;background:#006dac;padding:16px 32px;border-radius:8px;text-decoration:none;display:inline-block;transition:all 0.3s ease;box-shadow:0 4px 14px rgba(0,175,240,0.35)}\n.alt-cta-btn:hover{background:#003CC8;transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,175,240,0.45)}\n.alt-cta-note{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;margin-top:16px}\n.alt-model ul,.alt-model ol{list-style:none !important;padding:0 !important;margin:0 !important}.alt-model li{list-style:none !important}.alt-model li::before{display:none !important}\n@media(max-width:1024px){\n  .alt-comparison{grid-template-columns:1fr;gap:24px}\n  .alt-arrow{transform:rotate(90deg)}\n  .alt-benefits{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .alt-section{padding:80px 20px}\n  .alt-benefits{grid-template-columns:1fr}\n  .alt-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.alt-benefit,.alt-cta-btn{transition:none !important}}\n/* === PARTNER OFFERINGS (S5) === */\n.offer-section{background:#fff;padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.offer-box-inner{max-width:1200px;margin:0 auto}\n.offer-header{text-align:center;max-width:800px;margin:0 auto 60px}\n.offer-box-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.offer-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.offer-cards{display:grid;grid-template-columns:repeat(2,1fr);gap:32px;margin-bottom:48px}\n.offer-card{background:linear-gradient(135deg,#f8fafc,#fff);border:1px solid #e2e8f0;border-radius:20px;padding:40px;display:flex;gap:24px;text-decoration:none;transition:all 0.3s ease}\n.offer-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0,175,240,0.15);transform:translateY(-4px)}\n.offer-card-icon{width:72px;height:72px;background:linear-gradient(135deg,#00AFF0,#003CC8);border-radius:16px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.offer-card-icon svg{width:36px;height:36px;stroke:#fff;fill:none}\n.offer-card-content h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;font-weight:600;color:#000864;line-height:1.6;margin:0 0 12px;padding:0}\n.offer-card-content p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.6;margin:0 0 16px;padding:0}\n.offer-card-link{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:600;color:#0369a1;display:inline-flex;align-items:center;gap:8px}\n.offer-card-link svg{width:16px;height:16px;stroke:currentColor;transition:transform 0.2s}\n.offer-card:hover .offer-card-link svg{transform:translateX(4px)}\n.offer-box{background:linear-gradient(135deg,#000864 0%,#000432 100%);border-radius:20px;padding:48px;position:relative;overflow:hidden}\n.offer-box::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg width=\'40\' height=\'40\' viewBox=\'0 0 40 40\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Cpath d=\'M20 0l20 20-20 20L0 20z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.offer-box-inner{position:relative;z-index:1}\n.offer-box-title{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#fff;line-height:1.6;margin:0 0 32px;padding:0;text-align:center}\n.offer-checks{display:grid;grid-template-columns:repeat(4,1fr);gap:24px}\n.offer-check-item{display:flex;align-items:flex-start;gap:12px}\n.offer-check-item svg{width:24px;height:24px;stroke:#4ade80;flex-shrink:0;margin-top:2px}\n.offer-check-item span{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:rgba(255,255,255,0.9);line-height:1.5}\n@media(max-width:1024px){\n  .offer-cards{grid-template-columns:1fr;gap:24px}\n  .offer-checks{grid-template-columns:repeat(2,1fr)}\n  .offer-box{padding:40px}\n}\n@media(max-width:768px){\n  .offer-section{padding:80px 20px}\n  .offer-cards{grid-template-columns:1fr}\n  .offer-card{flex-direction:column}\n  .offer-checks{grid-template-columns:1fr}\n  .offer-box{padding:32px 24px}\n  .offer-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.offer-card,.offer-card-link svg{transition:none !important}}\n/* === JOURNEY SECTIONS (S6+S7) === */\n.journey-section{padding:100px 24px 120px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.journey-section--tiers{padding-top:60px}\n.journey-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.journey-header{text-align:center;max-width:800px;margin:0 auto 60px}\n.journey-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.journey-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.journey-steps{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;position:relative}\n.journey-steps--line::before{content:\'\';position:absolute;top:48px;left:12.5%;right:12.5%;height:3px;background:linear-gradient(90deg,#00AFF0,#10b981);border-radius:2px;z-index:0}\n.journey-step{text-align:center;position:relative;z-index:1}\n.journey-number{width:96px;height:96px;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px;box-shadow:0 8px 24px rgba(0,175,240,0.3)}\n.journey-number span{font-family:\'Noto Sans\',sans-serif;font-size:32px;font-weight:700;color:#fff}\n.journey-step h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 12px;padding:0}\n.journey-step p{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.journey-step-cta{display:inline-block;margin-top:16px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#0369a1;background:rgba(0,175,240,0.08);border:1px solid rgba(0,175,240,0.2);padding:10px 20px;border-radius:8px;text-decoration:none;transition:all 0.3s ease}\n.journey-step-cta:hover{background:rgba(0,175,240,0.15);border-color:#00AFF0;transform:translateY(-1px)}\n@media(max-width:1024px){\n  .journey-steps{grid-template-columns:repeat(2,1fr);gap:48px}\n  .journey-steps--line::before{display:none}\n}\n@media(max-width:768px){\n  .journey-section{padding:80px 20px}\n  .journey-section--tiers{padding-top:40px}\n  .journey-steps{grid-template-columns:1fr}\n  .journey-header{margin-bottom:40px}\n}\n@media(prefers-reduced-motion:reduce){.journey-step-cta{transition:none !important}}\n/* === MARKET TIMING (S8) === */\n.mkt-section{background:#F5F7FA;padding:80px 0 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mkt-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index: